const items = $input.all();
return items.map(i => ({
  json: {
    idpropriedade: i.json.idpropriedade,
    nomepropriedade: i.json.nomepropriedade,
    praca: i.json.praca,
    quartos: Number(i.json.quartos) || 1,
    latitude: String(i.json.latitude),
    longitude: String(i.json.longitude),
    titulo: i.json.nomepropriedade,
    proprietario: i.json.proprietario,
    meses_faltantes: Array.isArray(i.json.meses_faltantes) ? i.json.meses_faltantes : [],
    recordID: ''
  }
}));

// Recebe N itens long-format { idpropriedade, mes_ano, Base_ou_Nova, meta }
// Pivota para 1 item wide-format por (idpropriedade, Base_ou_Nova) com cada mes como coluna.
// Descarta metas zeradas/nulas (proteção contra falha do Gemini).
const items = $input.all();
if (items.length === 0) return [];

const grupos = {};
for (const it of items) {
  const d = it.json;
  const metaNum = Number(d.meta);
  if (!d.mes_ano || !isFinite(metaNum) || metaNum <= 0) continue;

  const key = `${d.idpropriedade}|${d.Base_ou_Nova || 'Base'}`;
  if (!grupos[key]) {
    grupos[key] = {
      IdPropriedade: d.idpropriedade,
      Base_ou_Nova: d.Base_ou_Nova || 'Base'
    };
  }
  grupos[key][d.mes_ano] = metaNum;
}

return Object.values(grupos)
  .filter(g => Object.keys(g).length > 2)
  .map(g => ({ json: g }));

// Mescla resultado do lookup com o payload original do pivot.
// Se o lookup retornou linha → existe na planilha.
// Se não retornou → propriedade nova.
const pivotItems = $('Pivot long→wide').all();
const lookupItems = $input.all();

const out = [];
for (let i = 0; i < pivotItems.length; i++) {
  const payload = pivotItems[i].json;
  const lookup = lookupItems[i]?.json || {};
  const existe = !!(lookup && lookup.IdPropriedade);
  out.push({ json: { ...payload, _existe: existe } });
}
return out;

// Lista inicial de propriedades detectadas (antes do loop)
const detectadas = $('Detectar propriedades com gap de meta').all();
const totalPropriedades = detectadas.length;
const totalMetas = detectadas.reduce((acc, it) => {
  const m = it.json.meses_faltantes;
  return acc + (Array.isArray(m) ? m.length : 0);
}, 0);

const unidades = detectadas.map(it => {
  const m = Array.isArray(it.json.meses_faltantes) ? it.json.meses_faltantes.length : 0;
  return `${it.json.idpropriedade} (+${m})`;
});

const resumo = totalPropriedades === 0
  ? 'Automação semanal de metas: nenhuma propriedade com gap detectada. ✅'
  : `Automação semanal de metas: *${totalPropriedades} propriedades* processadas, *${totalMetas} metas* inseridas.\nUnidades: ${unidades.slice(0, 25).join(', ')}${unidades.length > 25 ? '…' : ''}`;

return [{ json: { totalPropriedades, totalMetas, unidades, resumo } }];
